import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

// Create a favicon link if one doesn't exist
const createFavicon = () => {
  if (!document.querySelector("link[rel='icon']")) {
    const link = document.createElement('link');
    link.rel = 'icon';
    link.href = 'data:image/x-icon;base64,';
    document.head.appendChild(link);
  }
};

// Create basic meta tags if they don't exist
const ensureMetaTags = () => {
  if (!document.querySelector("meta[name='viewport']")) {
    const viewport = document.createElement('meta');
    viewport.name = 'viewport';
    viewport.content = 'width=device-width, initial-scale=1';
    document.head.appendChild(viewport);
  }
  
  if (!document.querySelector("meta[http-equiv='Permissions-Policy']")) {
    const policy = document.createElement('meta');
    policy.httpEquiv = 'Permissions-Policy';
    policy.content = 'interest-cohort=(), browsing-topics=()';
    document.head.appendChild(policy);
  }
};

// Run these functions
createFavicon();
ensureMetaTags();

const root = ReactDOM.createRoot(
  document.getElementById('root') as HTMLElement
);

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
); 